// BusinessException.java - Clase base
package com.paymentchange.customer.exceptions;

public class BusinessException extends RuntimeException {
    public BusinessException(String message) {
        super(message);
    }

    public BusinessException(String message, Throwable cause) {
        super(message, cause);
    }
}

// NotFoundException.java
public class NotFoundException extends BusinessException {
    public NotFoundException(String message) {
        super(message);
    }
}

// DuplicateResourceException.java
public class DuplicateResourceException extends BusinessException {
    public DuplicateResourceException(String message) {
        super(message);
    }
}

// InvalidStateException.java
public class InvalidStateException extends BusinessException {
    private String currentState;
    private String attemptedOperation;

    public InvalidStateException(String message) {
        super(message);
    }

    public InvalidStateException(String message, String currentState, 
                                String attemptedOperation) {
        super(message);
        this.currentState = currentState;
        this.attemptedOperation = attemptedOperation;
    }
}

// GlobalExceptionHandler - Handlers específicos
@RestControllerAdvice
@Slf4j
public class GlobalExceptionHandler {

    @ExceptionHandler(NotFoundException.class)
    public ResponseEntity<ErrorResponse> handleNotFound(
            NotFoundException ex, WebRequest request) {
        ErrorResponse error = new ErrorResponse(
            HttpStatus.NOT_FOUND.value(),
            "Not Found",
            ex.getMessage(),
            request.getDescription(false).replace("uri=", "")
        );
        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(error);
    }

    @ExceptionHandler(DuplicateResourceException.class)
    public ResponseEntity<ErrorResponse> handleDuplicate(
            DuplicateResourceException ex, WebRequest request) {
        ErrorResponse error = new ErrorResponse(
            HttpStatus.CONFLICT.value(),
            "Conflict",
            ex.getMessage(),
            request.getDescription(false).replace("uri=", "")
        );
        return ResponseEntity.status(HttpStatus.CONFLICT).body(error);
    }

    @ExceptionHandler(InvalidStateException.class)
    public ResponseEntity<ErrorResponse> handleInvalidState(
            InvalidStateException ex, WebRequest request) {
        ErrorResponse error = new ErrorResponse(
            HttpStatus.BAD_REQUEST.value(),
            "Invalid State",
            ex.getMessage(),
            request.getDescription(false).replace("uri=", "")
        );
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(error);
    }
}

// Uso en Service
public Customer create(Customer customer) {
    // Validar duplicado por email
    if (customerRepository.existsByEmail(customer.getEmail())) {
        throw new DuplicateResourceException(
            "Customer with email " + customer.getEmail() + " already exists"
        );
    }

    // Validar estado
    if (customer.getStatus().equals("INACTIVE") && 
        customer.getProductIds().size() > 0) {
        throw new InvalidStateException(
            "Cannot assign products to inactive customer",
            "INACTIVE",
            "ASSIGN_PRODUCTS"
        );
    }

    return customerRepository.save(customer);
}
